"""sklearn.compose — Column-wise transformers and target transformers."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin, RegressorMixin, clone


class ColumnTransformer(BaseEstimator, TransformerMixin):
    """Apply different transformers to different columns of an array.

    Parameters
    ----------
    transformers : list of (name, transformer, columns) tuples
    remainder : 'drop' or 'passthrough', default='drop'
    """

    def __init__(self, transformers, remainder='drop'):
        self.transformers = transformers
        self.remainder = remainder

    def fit(self, X, y=None):
        X = np.asarray(X)
        self.transformers_ = []
        self._remainder_cols = None
        used = set()
        for name, trans, cols in self.transformers:
            cols = self._resolve_cols(cols, X)
            used.update(cols)
            t = clone(trans)
            t.fit(X[:, cols], y)
            self.transformers_.append((name, t, cols))
        if self.remainder == 'passthrough':
            self._remainder_cols = sorted(set(range(X.shape[1])) - used)
        return self

    def transform(self, X):
        X = np.asarray(X)
        parts = []
        for name, t, cols in self.transformers_:
            out = t.transform(X[:, cols])
            if out.ndim == 1:
                out = out.reshape(-1, 1)
            parts.append(out)
        if self._remainder_cols:
            parts.append(X[:, self._remainder_cols])
        return np.hstack(parts) if parts else np.empty((X.shape[0], 0))

    @staticmethod
    def _resolve_cols(cols, X):
        if isinstance(cols, (list, tuple)):
            return list(cols)
        elif isinstance(cols, slice):
            return list(range(*cols.indices(X.shape[1])))
        elif callable(cols):
            return [i for i in range(X.shape[1]) if cols(i)]
        return [cols]


def make_column_transformer(*transformers, remainder='drop'):
    """Shorthand for ColumnTransformer with auto-generated names."""
    ts = [("t%d" % i, t, cols) for i, (t, cols) in enumerate(transformers)]
    return ColumnTransformer(ts, remainder=remainder)


class TransformedTargetRegressor(BaseEstimator, RegressorMixin):
    """Regressor that applies a transformation to the target before fitting.

    Parameters
    ----------
    regressor : estimator
    func : callable or None
    inverse_func : callable or None
    """

    def __init__(self, regressor=None, func=None, inverse_func=None):
        self.regressor = regressor
        self.func = func
        self.inverse_func = inverse_func

    def fit(self, X, y):
        y = np.asarray(y, dtype=float)
        self.regressor_ = clone(self.regressor)
        y_t = self.func(y) if self.func else y
        self.regressor_.fit(X, y_t)
        return self

    def predict(self, X):
        y_pred = self.regressor_.predict(X)
        if self.inverse_func:
            y_pred = self.inverse_func(y_pred)
        return y_pred
